Vtiger_Detail_Js("HelpDesk_Detail_Js",{setAccountsReference:function(){var e={module:"Accounts",view:"Popup",src_module:"HelpDesk",src_record:app.getRecordId()};Vtiger_Popup_Js.getInstance().show(e,function(e){var t=JSON.parse(e);$.each(t,function(e,t){Vtiger_Detail_Js.getInstance().saveFieldValues({field:"parent_id",value:e}).then(function(e){location.reload()})})})}},{registerSetServiceContracts:function(){var e=this;$(".selectServiceContracts").on("click","ul li",function(t){var r=jQuery(t.currentTarget);e.saveFieldValues({field:"servicecontractsid",value:r.data("id")}).then(function(e){location.reload()})})},registerTicketWorkflowModal:function(){jQuery(document).on("click",".js-ticket-workflow-submit",function(e){e.preventDefault();var t=jQuery("#ticketWorkflowForm");if(t.length){var r=t.data("mode"),o=t.data("record"),i=t.find('[name="solution"]').val()||"",s=t.find('[name="comment"]').val()||"";if("done"!==r||""!==jQuery.trim(i)){var n=jQuery.progressIndicator({});AppConnector.request({module:"HelpDesk",action:"TicketWorkflowAjax",record:o,mode:r,solution:i,comment:s}).then(function(e){if(n.progressIndicator({mode:"hide"}),e.success&&e.result&&e.result.success)return app.hideModalWindow(),void location.reload();var t=e.result&&e.result.message?e.result.message:"LBL_ERROR";Vtiger_Helper_Js.showPnotify({text:app.vtranslate(t,"HelpDesk"),type:"error"})},function(){n.progressIndicator({mode:"hide"}),Vtiger_Helper_Js.showPnotify({text:app.vtranslate("LBL_ERROR","Vtiger"),type:"error"})})}else Vtiger_Helper_Js.showPnotify({text:app.vtranslate("JS_LBL_TICKET_SOLUTION_REQUIRED","HelpDesk"),type:"error"})}})},registerEvents:function(){this._super(),this.registerSetServiceContracts(),this.registerTicketWorkflowModal()}});